namespace spk { DrawTextureMeshShadowRenderCommand::DrawTextureMeshShadowRenderCommand(std::shared_ptr<const TextureMesh3D> mesh, std::shared_ptr<UniformBufferObject> model, const Matrix4x4 &matrix) : _mesh(std::move(mesh)), _model(std::move(model)), _shadow(7, BufferObject::Usage::StaticDraw, sizeof(matrix)) { _shadow.edit(&matrix, sizeof(matrix)); } void DrawTextureMeshShadowRenderCommand::execute(RenderContext &context) { if (!_mesh || !_model || _mesh->layoutBuffer().indexCount()==0) return; OpenGLDrawStateGuard guard; glEnable(GL_CULL_FACE); glCullFace(GL_BACK); glFrontFace(GL_CCW); glEnable(GL_DEPTH_TEST); glDepthMask(GL_TRUE); glDisable(GL_BLEND); static Program program(SPARKLE_GET_RESOURCE_AS_STRING("resources/shaders/mesh_3d/draw_shadow.vert"), SPARKLE_GET_RESOURCE_AS_STRING("resources/shaders/mesh_3d/draw_shadow.frag")); program.activate(context); _model->activate(context); _shadow.activate(context); _mesh->layoutBuffer().activate(context); program.render(context, Primitive::Triangles, 0, _mesh->layoutBuffer().indexCount()); } }
